// ─── Write Article via OpenCode/Gemini ────────────────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const routeData = $('Route by Command').first().json;
const topic  = routeData.topic;
const chatId = routeData.chatId;
const msgId  = routeData.msgId;

const prompt = `당신은 전문 블로그 작가입니다. 아래 주제를 바탕으로 네이버 블로그에 올릴 완성도 높은 글을 HTML 형식으로 작성해주세요.\n\n주제: ${topic}\n\n요구사항:\n- 제목(title)과 본문(content)을 JSON 형식으로 반환하세요\n- 본문은 HTML 태그를 사용하세요 (<h2>, <p>, <ul>, <li>, <strong>, <em> 등)\n- 최소 1000자 이상 작성\n- 소제목을 3~5개 포함\n- 독자 친화적이고 SEO에 최적화된 글\n- 마지막에 요약/결론 섹션 포함\n\n반드시 아래 JSON 형식으로만 답변하세요 (다른 텍스트 없이):\n{"title": "글 제목", "content": "<html 본문>"}`;

try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: `${OPENCODE_URL}/run`,
    body: { prompt },
    json: true,
    timeout: 120000
  });

  let rawText = result.text || '';
  const jsonMatch = rawText.match(/\{[\s\S]*\"title\"[\s\S]*\"content\"[\s\S]*\}/);
  if (!jsonMatch) {
    return [{ json: { chatId, msgId, title: `${topic}에 대한 정리`, content: `<p>${rawText.slice(0, 3000)}</p>` } }];
  }

  const parsed = JSON.parse(jsonMatch[0]);
  return [{ json: { chatId, msgId, title: parsed.title, content: parsed.content } }];
} catch(e) {
  return [{ json: { chatId, msgId, title: `${topic} - 블로그 글`, content: `<h2>${topic}</h2><p>오류: ${e.message}</p>`, writeError: e.message } }];
}

// ─── Format Article for Telegram ─────────────────────────────────────────
const { chatId, msgId, title, content } = $json;

function stripHTML(html) {
  return String(html || '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/?(h[1-6]|p|li|div|tr)>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const plainContent = stripHTML(content);

// Telegram message limit is 4096 chars; reserve space for title header
const MAX_CONTENT = 3800;
const truncated = plainContent.length > MAX_CONTENT
  ? plainContent.slice(0, MAX_CONTENT) + '\n\n... (내용이 길어 일부 생략되었습니다)'
  : plainContent;

const formattedText = `📰 <b>${title}</b>\n\n${truncated}`;

return [{ json: { chatId, msgId, title, content, formattedText } }];

// ─── Run OpenCode ────────────────────────────────────────────────────────────
// NOTE: $json here is the Telegram ACK response — pull real data from router.
const OPENCODE_URL = 'http://opencode-proxy:3284';
const TIMEOUT = 300000;

const routeData = $('Route by Command').first().json;
const message = routeData.message || '';
const chatId  = routeData.chatId;
const msgId   = routeData.msgId;

if (!message) {
  return [{ json: { chatId, msgId, formattedText: '(메시지가 비어있습니다)' } }];
}

function escapeHTML(str) {
  return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: `${OPENCODE_URL}/run`,
    body: { prompt: message },
    json: true,
    timeout: TIMEOUT
  });

  const model = result.model || 'OpenCode';
  let text = result.text || '(no output)';

  if (text.length > 3900) {
    text = text.slice(0, 3900) + "\n\n... (Truncated)";
  }

  const formattedText = `🤖 <b>Model:</b> <code>${escapeHTML(model)}</code>\n\n${escapeHTML(text)}`;

  return [{ json: { chatId, msgId, formattedText, model, text } }];
} catch (e) {
  const errMsg = (e.message || '').slice(0, 500);
  const formattedText = `❌ <b>오류:</b>\n<pre>${escapeHTML(errMsg)}</pre>`;
  return [{ json: { chatId, msgId, formattedText, error: true } }];
}
